1	import { readFileSync } from "node:fs";
2	import { quote, claim } from "./claim-office.js";
3	
4	type Step = any;
5	
6	const KNOWN_ITEM_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
7	
8	function validateItems(items: Step[]): void {
9	  for (const item of items) {
10	    if (!KNOWN_ITEM_TYPES.includes(item.type)) {
11	      throw new Error(`Unknown item type: ${item.type}`);
12	    }
13	  }
14	}
15	
16	function executeQuote(step: Step, years: number): any {
17	  validateItems(step.items);
18	  return quote({ items: step.items, years, priorContract: false });
19	}
20	
21	function validateDamageEntries(damages: Step[]): void {
22	  for (const damage of damages) {
23	    if (damage.amount < 0) {
24	      throw new Error(`Damage amount cannot be negative: ${damage.amount}`);
25	    }
26	  }
27	}
28	
29	function validateDamagesAgainstPolicy(damages: Step[], policyItems: Step[]): void {
30	  const policyItemTypes = policyItems.map((i: any) => i.type);
31	  for (const damage of damages) {
32	    if (!policyItemTypes.includes(damage.itemType)) {
33	      throw new Error(`Damage references item not in policy: ${damage.itemType}`);
34	    }
35	  }
36	}
37	
38	function executeClaim(step: Step, steps: Step[]): any {
39	  const referencedQuote = steps[step.policy];
40	  validateDamageEntries(step.incident.damages);
41	  validateDamagesAgainstPolicy(step.incident.damages, referencedQuote.items);
42	  return claim({ policy: { items: referencedQuote.items }, incident: step.incident });
43	}
44	
45	function executeStep(step: Step, steps: Step[], years: number): any {
46	  if (step.op === "claim") {
47	    return executeClaim(step, steps);
48	  }
49	  return executeQuote(step, years);
50	}
51	
52	try {
53	  const scenario = JSON.parse(readFileSync(0, "utf-8"));
54	  const years = scenario.customer.yearsWithMHPCO;
55	  const steps: Step[] = scenario.steps;
56	  const results = steps.map((step) => executeStep(step, steps, years));
57	  process.stdout.write(JSON.stringify({ results }));
58	} catch (e: any) {
59	  process.stderr.write(`Error: ${e.message}\n`);
60	  process.exit(1);
61	}
